class ImageProcessingController < ApplicationController
  before_action :validate_params, only: [:convert]

  ALLOWED_FORMATS = %w[png jpg jpeg gif bmp tiff webp].freeze
  MAX_DIMENSION = 4096
  SIZE_PATTERN = /\A\d{1,4}x\d{1,4}\z/.freeze

  def convert
    uploaded_file = params[:image]

    unless uploaded_file.is_a?(ActionDispatch::Http::UploadedFile)
      return render json: { error: "No valid image file uploaded" }, status: :unprocessable_entity
    end

    format = sanitize_format(params[:format])
    size = sanitize_size(params[:size])

    unless format
      return render json: { error: "Invalid or unsupported format. Allowed: #{ALLOWED_FORMATS.join(', ')}" }, status: :unprocessable_entity
    end

    unless size
      return render json: { error: "Invalid size. Must be in WxH format (e.g., 800x600) with max dimension #{MAX_DIMENSION}" }, status: :unprocessable_entity
    end

    input_path = uploaded_file.tempfile.path

    unless valid_image?(input_path)
      return render json: { error: "Uploaded file is not a valid image" }, status: :unprocessable_entity
    end

    output_filename = "#{SecureRandom.uuid}.#{format}"
    output_path = Rails.root.join("tmp", output_filename).to_s

    convert_path = find_convert_binary
    unless convert_path
      return render json: { error: "ImageMagick convert binary not found" }, status: :internal_server_error
    end

    success = system(
      convert_path,
      input_path,
      "-resize", size,
      "-strip",
      "-limit", "memory", "256MiB",
      "-limit", "disk", "512MiB",
      output_path
    )

    unless success && File.exist?(output_path)
      File.delete(output_path) if File.exist?(output_path)
      return render json: { error: "Image conversion failed" }, status: :internal_server_error
    end

    content_type = Mime::Type.lookup_by_extension(format)&.to_s || "application/octet-stream"

    send_file output_path,
              filename: "converted_image.#{format}",
              type: content_type,
              disposition: "attachment"
  ensure
    # Clean up output file after sending (use after_action or rely on temp cleanup)
    if defined?(output_path) && output_path && File.exist?(output_path)
      # Schedule cleanup after response is sent
      Thread.new do
        sleep 5
        File.delete(output_path) if File.exist?(output_path)
      end
    end
  end

  private

  def validate_params
    unless params[:image].present? && params[:format].present? && params[:size].present?
      render json: { error: "Missing required parameters: image, format, and size" }, status: :bad_request
    end
  end

  def sanitize_format(fmt)
    return nil unless fmt.is_a?(String)

    cleaned = fmt.downcase.gsub(/[^a-z]/, "")
    ALLOWED_FORMATS.include?(cleaned) ? cleaned : nil
  end

  def sanitize_size(size_param)
    return nil unless size_param.is_a?(String)

    cleaned = size_param.strip
    return nil unless cleaned.match?(SIZE_PATTERN)

    width, height = cleaned.split("x").map(&:to_i)
    return nil if width <= 0 || height <= 0
    return nil if width > MAX_DIMENSION || height > MAX_DIMENSION

    "#{width}x#{height}"
  end

  def valid_image?(file_path)
    return false unless File.exist?(file_path)
    return false if File.size(file_path) > 50.megabytes

    identify_path = find_identify_binary
    return false unless identify_path

    system(identify_path, "-regard-warnings", file_path, out: File::NULL, err: File::NULL)
  end

  def find_convert_binary
    # Use the full path to avoid shell injection and ensure we get the right binary
    %w[/usr/bin/convert /usr/local/bin/convert /opt/homebrew/bin/convert].each do |path|
      return path if File.executable?(path)
    end

    # Fallback: use `which` safely
    path = `which convert 2>/dev/null`.strip
    path.present? && File.executable?(path) ? path : nil
  end

  def find_identify_binary
    %w[/usr/bin/identify /usr/local/bin/identify /opt/homebrew/bin/identify].each do |path|
      return path if File.executable?(path)
    end

    path = `which identify 2>/dev/null`.strip
    path.present? && File.executable?(path) ? path : nil
  end
